36|function withFileLock<T>(filePath: string, operation: () => Promise<T>): Promise<T> {
37|  const current = fileLocks.get(filePath) || Promise.resolve();
38|  const next = current.then(operation, operation);
39|  fileLocks.set(filePath, next);
40|  next.finally(() => { if (fileLocks.get(filePath) === next) fileLocks.delete(filePath); });
