1|/**
2| * SUNy Symbol Reader — regex-based function/class/variable/export map.
3| *
4| * F2a deliverable: gives the AI a structural view of a JS/TS file without
5| * reading the full content. Reduces context usage on large files and
6| * improves edit precision by showing exact symbol locations.
7| *
8| * No native dependencies — pure regex. Falls back gracefully for non-JS/TS.
9| */
10|
11|import { tool } from 'ai';
12|import { z } from 'zod';
13|import { sendToBridge, isBridgeConnected } from './bridge-manager';
14|
15|// ─────────────────────────────────────────────────────────────────────────────
16|// Types
17|// ─────────────────────────────────────────────────────────────────────────────
18|
19|export interface SymbolEntry {
20|  name: string;
21|  kind: 'function' | 'class' | 'interface' | 'type' | 'variable' | 'enum' | 'method' | 'property';
22|  exported: boolean;
23|  line: number;
24|  defaultExport: boolean;
25|}
26|
27|export interface SymbolMap {
28|  filePath: string;
29|  symbols: SymbolEntry[];
30|  language: string;
31|  lineCount: number;
32|}
33|
34|// ─────────────────────────────────────────────────────────────────────────────
35|// Regex patterns for JS/TS symbol extraction
36|// ─────────────────────────────────────────────────────────────────────────────
37|
38|interface SymbolPattern {
39|  regex: RegExp;
40|  kind: SymbolEntry['kind'];
41|}
42|
43|const EXPORT_PATTERNS: SymbolPattern[] = [
44|  { regex: /export\s+default\s+(?:async\s+)?function\s+(\w+)/g,   kind: 'function' },
45|  { regex: /export\s+default\s+class\s+(\w+)/g,                     kind: 'class' },
46|  { regex: /export\s+default\s+(?:const|let|var)\s+(\w+)/g,          kind: 'variable' },
47|  { regex: /export\s+function\s+(\w+)/g,                             kind: 'function' },
48|  { regex: /export\s+(?:async\s+)?function\s+(\w+)/g,                kind: 'function' },
49|  { regex: /export\s+class\s+(\w+)/g,                                kind: 'class' },
50|  { regex: /export\s+(?:abstract\s+)?class\s+(\w+)/g,                kind: 'class' },
51|  { regex: /export\s+interface\s+(\w+)/g,                            kind: 'interface' },
52|  { regex: /export\s+type\s+(\w+)\s*=/g,                             kind: 'type' },
53|  { regex: /export\s+(?:const|let|var)\s+(\w+)/g,                    kind: 'variable' },
54|  { regex: /export\s+enum\s+(\w+)/g,                                 kind: 'enum' },
55|];
56|
57|const DECLARATION_PATTERNS: SymbolPattern[] = [
58|  { regex: /(?:^|\n)\s*(?:async\s+)?function\s+(\w+)\s*\(/g,        kind: 'function' },
59|  { regex: /(?:^|\n)\s*(?:export\s+)?(?:abstract\s+)?class\s+(\w+)/g, kind: 'class' },
60|  { regex: /(?:^|\n)\s*(?:export\s+)?interface\s+(\w+)/g,           kind: 'interface' },
61|  { regex: /(?:^|\n)\s*(?:export\s+)?type\s+(\w+)\s*=/g,            kind: 'type' },
62|  { regex: /(?:^|\n)\s*(?:export\s+)?enum\s+(\w+)/g,                kind: 'enum' },
63|  { regex: /(?:^|\n)\s*(?:export\s+)?(?:const|let|var)\s+(\w+)\s*(?::|=)/g, kind: 'variable' },
64|];
65|
66|// ─────────────────────────────────────────────────────────────────────────────
67|// Extraction
68|// ─────────────────────────────────────────────────────────────────────────────
69|
70|/**
71| * Extract symbol entries from file content.
72| * Deduplicates by name — prefers exported over non-exported, keeps first occurrence.
73| */
74|export function extractSymbols(content: string, fileName: string): SymbolMap {
75|  const lines = content.split('\n');
76|  const symbolMap = new Map<string, SymbolEntry>();
77|
78|  // Helper to add a symbol (prefer exported, keep first)
79|  const addSymbol = (name: string, kind: SymbolEntry['kind'], line: number, exported: boolean, defaultExport: boolean) => {
80|    const existing = symbolMap.get(name);
81|    if (existing) {
82|      // Prefer exported over non-exported
83|      if (exported && !existing.exported) {
84|        symbolMap.set(name, { name, kind, exported, line, defaultExport });
85|      }
86|      return;
87|    }
88|    symbolMap.set(name, { name, kind, exported, line, defaultExport });
89|  };
90|
91|  // Scan export patterns first (prefer exported status)
92|  for (const { regex, kind } of EXPORT_PATTERNS) {
93|    regex.lastIndex = 0;
94|    let match: RegExpExecArray | null;
95|    while ((match = regex.exec(content)) !== null) {
96|      const name = match[1];
97|      // Find approximate line number
98|      const line = getLineNumber(content, match.index);
99|      const isDefault = content.slice(match.index, match.index + match[0].length).startsWith('export default');
100|      addSymbol(name, kind, line, true, isDefault);
101|    }
102|  }
103|
104|  // Scan declarations — only add if not already captured as exported
105|  for (const { regex, kind } of DECLARATION_PATTERNS) {
106|    regex.lastIndex = 0;
107|    let match: RegExpExecArray | null;
108|    while ((match = regex.exec(content)) !== null) {
109|      const name = match[1];
110|      if (!symbolMap.has(name)) {
111|        const line = getLineNumber(content, match.index);
112|        addSymbol(name, kind, line, false, false);
113|      }
114|    }
115|  }
116|
117|  // Detect methods inside classes (indented function declarations)
118|  const methodRegex = /(?:^|\n)(\s+)(?:async\s+)?(\w+)\s*\([^)]*\)\s*\{/g;
119|  let match: RegExpExecArray | null;
120|  while ((match = methodRegex.exec(content)) !== null) {
121|    const indent = match[1];
122|    const name = match[2];
123|    // Only count as method if indented (inside a class/object)
124|    if (indent.length >= 2 && !symbolMap.has(name)) {
125|      const line = getLineNumber(content, match.index);
126|      // Skip if it looks like a standalone function (no indentation)
127|      addSymbol(name, 'method', line, false, false);
128|    }
129|  }
130|
131|  const lang = detectLanguage(fileName);
132|
133|  return {
134|    filePath: fileName,
135|    symbols: Array.from(symbolMap.values()),
136|    language: lang,
137|    lineCount: lines.length,
138|  };
139|}
140|
141|// ─────────────────────────────────────────────────────────────────────────────
142|// Helpers
143|// ─────────────────────────────────────────────────────────────────────────────
144|
145|function getLineNumber(content: string, index: number): number {
146|  return content.slice(0, index).split('\n').length;
147|}
148|
149|function detectLanguage(fileName: string): string {
150|  const ext = fileName.split('.').pop()?.toLowerCase() || '';
151|  switch (ext) {
152|    case 'ts': case 'tsx': return 'TypeScript';
153|    case 'js': case 'jsx': case 'mjs': case 'cjs': return 'JavaScript';
154|    case 'py': return 'Python';
155|    case 'go': return 'Go';
156|    case 'rs': return 'Rust';
157|    case 'java': return 'Java';
158|    case 'rb': return 'Ruby';
159|    case 'php': return 'PHP';
160|    case 'css': case 'scss': case 'less': return 'Stylesheet';
161|    case 'json': return 'JSON';
162|    case 'md': return 'Markdown';
163|    case 'yaml': case 'yml': return 'YAML';
164|    default: return 'Unknown';
165|  }
166|}
167|
168|// ─────────────────────────────────────────────────────────────────────────────
169|// Format for AI consumption
170|// ─────────────────────────────────────────────────────────────────────────────
171|
172|/**
173| * Format a SymbolMap into a compact string for the AI.
174| */
175|export function formatSymbolMap(map: SymbolMap): string {
176|  if (map.symbols.length === 0) {
177|    return `[${map.filePath}] — ${map.language}, ${map.lineCount} lines. No symbols detected.`;
178|  }
179|
180|  const maxNameLen = Math.max(...map.symbols.map(s => s.name.length));
181|  const lines: string[] = [
182|    `📄 ${map.filePath} — ${map.language}, ${map.lineCount} lines, ${map.symbols.length} symbols`,
183|    '',
184|  ];
185|
186|  for (const sym of map.symbols) {
187|    const marker = sym.exported ? (sym.defaultExport ? '⬇' : '📤') : '  ';
188|    const lineStr = `L${String(sym.line).padStart(4)}`;
189|    const namePadded = sym.name.padEnd(maxNameLen);
190|    lines.push(`  ${marker} ${lineStr}  ${namePadded}  ${sym.kind}`);
191|  }
192|
193|  return lines.join('\n');
194|}
195|
196|// ─────────────────────────────────────────────────────────────────────────────
197|// Tool factory
198|// ─────────────────────────────────────────────────────────────────────────────
199|
200|export function createSymbolReaderTool(ctx: { userId: number; projectPath: string }) {
201|  const { userId, projectPath } = ctx;
202|
203|  return tool({
204|    description:
205|      'Read the symbol structure of a file (functions, classes, interfaces, types, variables, enums) ' +
206|      'without reading the full content. Returns symbol names, kinds, export status, and line numbers. ' +
207|      'Use this to understand a file\'s structure before editing — saves tokens vs reading the whole file. ' +
208|      'Supports JS/TS, Python, Go, Rust, Java, and others.',
209|    inputSchema: z.object({
210|      filePath: z.string().describe('Path to the file (relative to WorkingDirectory, or absolute).'),
211|    }),
212|    execute: async ({ filePath }) => {
213|      if (!isBridgeConnected(userId)) {
214|        return 'Bridge not connected. Cannot read file.';
215|      }
216|
217|      const absPath = filePath.startsWith('/') || filePath.startsWith('~')
218|        ? filePath
219|        : `${projectPath}/${filePath}`;
220|
221|      try {
222|        const rawContent = await sendToBridge(userId, 'exec:read_file', {
223|          path: absPath,
224|          withLines: false,
225|        }, 15000) as string | undefined;
226|
227|        if (!rawContent) {
228|          return `File '${filePath}' is empty or could not be read.`;
229|        }
230|
231|        const symbolMap = extractSymbols(
232|          (rawContent as string).replace(/\r\n/g, '\n'),
233|          filePath,
234|        );
235|
236|        return formatSymbolMap(symbolMap);
237|      } catch (e) {
238|        return `Error reading symbols from '${filePath}': ${e instanceof Error ? e.message : String(e)}`;
239|      }
240|    },
241|  });
242|}
